import{_ as o}from"./chunks/robocode-battle-anim.P1Knszk8.js";import{_ as t,c as a,o as r,ag as n}from"./chunks/framework.CgegSSb6.js";const i="/images/tank.svg",g=JSON.parse('{"title":"What is Robocode?","description":"","frontmatter":{},"headers":[],"relativePath":"articles/intro.md","filePath":"articles/intro.md"}'),s={name:"articles/intro.md"};function l(h,e,d,c,m,p){return r(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="what-is-robocode" tabindex="-1">What is Robocode? <a class="header-anchor" href="#what-is-robocode" aria-label="Permalink to &quot;What is Robocode?&quot;">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>Robocode is a <a href="https://en.wikipedia.org/wiki/Programming_game" title="Programming Game" target="_blank" rel="noreferrer">programming game</a> where the goal is to code a bot. The bot is a tank that must compete against other tanks in a virtual battle arena.</p><p><img src="'+i+'" alt="Tank image"></p><p>The &quot;player&quot; of the game is the programmer (coder) of the bot, who will have no direct influence on the game while it is running. Instead, the player (&quot;Robocoder&quot;) must write a program that makes up the brain of the tank. The program (code) tells how the tank must behave and react to events occurring in the battle arena.</p><p>The code should tell the tank how to move around on the battlefield and avoid getting shot by enemies while moving around in different situations. And at the same time, the tank must scan for enemy tanks by turning its radar and firing its gun towards enemy tanks.</p><p>All bots (tanks) get a score and a placement depending on how well they performed on the battlefield. So the aim is to get as high score and placement as possible.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The game is designed to help you learn how to program, improve your programming skills, and have fun while doing it. Robocode is also useful when studying or improving <a href="https://en.wikipedia.org/wiki/Artificial_intelligence" title="AI: Artificial Intelligence" target="_blank" rel="noreferrer">AI</a> in a fast-running real-time game.</p><p>Sometimes people lack something to get started with when learning how to code or something to train AI skills against. Robocode gives a clear purpose and goal to the programming. To develop a tank that can survive on the battlefield and defeat other enemy tanks.</p><p>Head over to <a href="./../tutorial/getting-started.html">Getting Started</a> to get started with Robocoding!</p><h2 id="the-book-of-robocode" tabindex="-1">The Book of Robocode <a class="header-anchor" href="#the-book-of-robocode" aria-label="Permalink to &quot;The Book of Robocode&quot;">​</a></h2><p>For a deeper dive into advanced strategies and techniques, check out 📖 <a href="https://book.robocode.dev/" target="_blank" rel="noreferrer"><strong>The Book of Robocode</strong></a>. This comprehensive guide covers both Robocode and Tank Royale—from basics to advanced strategies like wave surfing, guess-factor targeting, and movement techniques. It builds on two decades of community knowledge and foundational research from RoboWiki contributors.</p><h2 id="the-name-robocode" tabindex="-1">The name &quot;Robocode&quot; <a class="header-anchor" href="#the-name-robocode" aria-label="Permalink to &quot;The name &quot;Robocode&quot;&quot;">​</a></h2><p>The name <em>Robocode</em> originates from the <a href="https://robocode.sourceforge.io/" target="_blank" rel="noreferrer">original version</a> of the game and is a short for &quot;Robot code&quot;. With this new version, the world &quot;bot&quot; is used instead of &quot;robot&quot;.</p><h2 id="the-name-tank-royale" tabindex="-1">The name &quot;Tank Royale&quot; <a class="header-anchor" href="#the-name-tank-royale" aria-label="Permalink to &quot;The name &quot;Tank Royale&quot;&quot;">​</a></h2><p>Robocode&#39;s battles take place on a battlefield, where small automated tank bots fight it out until only one is left like a Battle Royale Game. Hence, the name <em>Tank Royale</em>.</p><blockquote><p>Please notice that Robocode contains no gore, no blood, no people, and no politics. The battles are simply for the excitement of the competition (sport) that we love so much.</p></blockquote><h3 id="example-of-a-robocode-battle" tabindex="-1">Example of a Robocode battle <a class="header-anchor" href="#example-of-a-robocode-battle" aria-label="Permalink to &quot;Example of a Robocode battle&quot;">​</a></h3><p><img src="'+o+'" alt="Battle screenshot"></p>',20)])])}const f=t(s,[["render",l]]);export{g as __pageData,f as default};
